import { useDispatch, useSelector } from "react-redux";
import { useHistory } from "react-router";
import CartSlice, { addToCart } from "../slices/cartSlice";
import { useGetAllProductsQuery } from "../slices/productsApi";
import Cart from "./Cart"

const Home = () => {
  const { items: products, status } = useSelector((state) => state.products);
  const dispatch = useDispatch();
  const history = useHistory();

  const { data, error, isLoading } = useGetAllProductsQuery();
  console.log("mera data",data)
  console.log("Api", isLoading);

  const handleAddToCart = (product) => {
    dispatch(addToCart(product));
    history.push("/cart");
  };

  return (
    <div className="home-container">
      {status === "success" ? (
        <>
          <h2>New Arrivals</h2>
          <div className="products">
            {data && 
              data?.map((product) => (
                <div key={product.id} className="product">
                  <h3>{product.name}</h3>
                  <img src={product.image} alt={product.name} />
                  <div className="details">
                    <span className="">{product.desc}</span>
                    <span className="price">${product.price}</span>
                  </div>
                  <button onClick={() => handleAddToCart(product)}>
                    Add To Cart
                  </button>
                </div>
              ))}
          </div>
        </>
      ) : status === "pending" ? (
        <p>Loading...</p>
      ) : (
        <p>Unexpected error occured...</p>
      )}




      {/* <div><Cart /></div> */}


      {data.map((item) => {
          return (
            <div className=" block col-3 row ">
              <div className="">
                <span>{item.id}</span>
              </div>
              <p className="">{item.cat_name}</p>
              <div className="">
                <div className="">
                  {item?.products?.map((product, index) => (
                    <div className="" key={index}>
                      <div className="">
                        <div className="">
                          <img src={product.image} />
                        </div>
                        <div className="">
                        {product.id}
                          <h4>{product.name}</h4>
                          <div className="">
                            <span>{product.image} </span>
                            <small className=""></small>
                            <span>{product.pro_desc}</span>
                          </div>
                          <span>{product.price}</span>
                          <div>


                            <button
                              type="button"
                              className="btn"
                              // onClick={() => HandleClick(product)}
                            >
                              Add to Cart
                            </button>
                          </div>
                        </div>
                      </div>
                    </div>

                    /* <li>
                     <div className="product">
                         <div className="product-image">

                           <h1>{products.name}
                        <p>   {products.image}</p>
                           </h1>

                           <p>{products.price}</p>
                         </div> */
                    /* </div>
                   </li> */

                    /* <div className="product-imformation">
                            <h4>{content.name}</h4>
                            <div className="specification">
                              <span>{content.ram} RAM</span>
                              <small className="line"></small>
                              <span>{content.ssd} SSD</span>
                            </div>
                            <span>${content.price}</span>
                         </div> */
                  ))}
                </div>
              </div>
            </div>
          );
        })}
    </div>
  );
};

export default Home;
